142	uint8_t findTarget(uint8_t array[SIZE], uint8_t x, uint8_t stop)
143	{
144		uint8_t t;
145		// if the position is already on the first, don't evaluate
146		if (x == 0)
147		{
148			return x;
149		}
150		for (t = x - 1;; t--)
151		{
152			if (array[t] != 0)
153			{
154				if (array[t] != array[x])
155				{
156					// merge is not possible, take next position
157					return t + 1;
158				}
159				return t;
160			}
161			else
162			{
163				// we should not slide further, return this one
164				if (t == stop)
165				{
166					return t;
167				}
168			}
169		}
170		// we did not find a target
171		return x;
172	}
173	
174	bool slideArray(uint8_t array[SIZE], uint32_t *score)
175	{
176		bool success = false;
177		uint8_t x, t, stop = 0;
178	
179		for (x = 0; x < SIZE; x++)
180		{
181			if (array[x] != 0)
182			{
183				t = findTarget(array, x, stop);
184				// if target is not original position, then move or merge
185				if (t != x)
186				{
187					// if target is zero, this is a move
188					if (array[t] == 0)
189					{
190						array[t] = array[x];
191					}
192					else if (array[t] == array[x])
193					{
194						// merge (increase power of two)
195						array[t]++;
196						// increase score
197						*score += 1 << array[t];
198						// set stop to avoid double merge
199						stop = t + 1;
200					}
201					array[x] = 0;
202					success = true;
203				}
204			}
205		}
206		return success;
207	}
