258	bool moveUp(uint8_t board[SIZE][SIZE], uint32_t *score)
259	{
260		bool success = false;
261		uint8_t x;
262		for (x = 0; x < SIZE; x++)
263		{
264			success |= slideArray(board[x], score);
265		}
266		return success;
267	}
268	
269	bool moveLeft(uint8_t board[SIZE][SIZE], uint32_t *score)
270	{
271		bool success;
272		rotateBoard(board);
273		success = moveUp(board, score);
274		rotateBoard(board);
275		rotateBoard(board);
276		rotateBoard(board);
277		return success;
278	}
279	
280	bool moveDown(uint8_t board[SIZE][SIZE], uint32_t *score)
281	{
282		bool success;
283		rotateBoard(board);
284		rotateBoard(board);
285		success = moveUp(board, score);
286		rotateBoard(board);
287		rotateBoard(board);
288		return success;
289	}
290	
291	bool moveRight(uint8_t board[SIZE][SIZE], uint32_t *score)
292	{
293		bool success;
294		rotateBoard(board);
295		rotateBoard(board);
296		rotateBoard(board);
297		success = moveUp(board, score);
298		rotateBoard(board);
299		return success;
300	}
301	
302	// findPairDown returns true exactly when some vertically adjacent pair of cells
303	// is equal, i.e. board[x][y] == board[x][y+1] for some 0<=x<SIZE, 0<=y<SIZE-1.
304	// In the flattened 16-byte board such a pair is cells a and a+1 where a is any
305	// index that is not the last entry of its column (a % SIZE != SIZE-1). Phrasing
306	// the property as a single existential quantifier keeps it a one-constraint
307	// check, cheap enough to be reached under CBMC's shallow --depth bound (a fully
308	// expanded 12-way disjunction is not). It still pins down the exact comparison,
309	// the exact pair offset (+1), and the exact ranges, killing mutations of each.
310	#define FPD_ANY_PAIR                                                  \
311		__CPROVER_exists                                                  \
312		{                                                                \
313			int _a;                                                      \
314			(0 <= _a && _a < SIZE *SIZE && (_a % SIZE) != SIZE - 1) &&   \
315				((const uint8_t *)board)[_a] == ((const uint8_t *)board)[_a + 1] \
316		}
317	
318	bool findPairDown(uint8_t board[SIZE][SIZE])
319	// clang-format off
320	// the board must be a readable 4x4 block of bytes
321	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
322	// findPairDown only reads the board; it writes nothing
323	__CPROVER_assigns()
324	// the result is true exactly when some vertically adjacent pair is equal
325	__CPROVER_ensures(__CPROVER_return_value == (FPD_ANY_PAIR))
326	// clang-format on
327	{
328		bool success = false;
329		uint8_t x, y;
330		for (x = 0; x < SIZE; x++)
331		{
332			for (y = 0; y < SIZE - 1; y++)
333			{
334				if (board[x][y] == board[x][y + 1])
335					return true;
336			}
337		}
338		return success;
339	}
340	
341	// Indicator (0 or 1) for cell `i` of the flattened board being empty (== 0).
342	#define CE_EMPTY(i) (((const uint8_t *)board)[i] == 0)
343	// Exact number of empty cells in the flattened 4x4 board, as a literal sum so
344	// CBMC pins down the precise count (not just a bound), killing mutations of the
345	// comparison, the increment, and the loop bounds.
346	#define CE_TOTAL ( \
347		CE_EMPTY(0)  + CE_EMPTY(1)  + CE_EMPTY(2)  + CE_EMPTY(3)  + \
348		CE_EMPTY(4)  + CE_EMPTY(5)  + CE_EMPTY(6)  + CE_EMPTY(7)  + \
349		CE_EMPTY(8)  + CE_EMPTY(9)  + CE_EMPTY(10) + CE_EMPTY(11) + \
350		CE_EMPTY(12) + CE_EMPTY(13) + CE_EMPTY(14) + CE_EMPTY(15))
351	
352	uint8_t countEmpty(uint8_t board[SIZE][SIZE])
353	// clang-format off
354	// the board must be a readable 4x4 block of bytes
355	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
356	// countEmpty only reads the board; it writes nothing
357	__CPROVER_assigns()
358	// the result is exactly the number of empty (zero-valued) cells
359	__CPROVER_ensures(__CPROVER_return_value == CE_TOTAL)
360	// clang-format on
361	{
362		uint8_t x, y;
363		uint8_t count = 0;
364		for (x = 0; x < SIZE; x++)
365		{
366			for (y = 0; y < SIZE; y++)
367			{
368				if (board[x][y] == 0)
369				{
370					count++;
371				}
372			}
373		}
374		return count;
375	}
376	
377	bool gameEnded(uint8_t board[SIZE][SIZE])
378	{
379		bool ended = true;
380		if (countEmpty(board) > 0)
381			return false;
382		if (findPairDown(board))
383			return false;
384		rotateBoard(board);
385		if (findPairDown(board))
386			ended = false;
387		rotateBoard(board);
388		rotateBoard(board);
389		rotateBoard(board);
390		return ended;
391	}
392	
393	// Stub for srand: it has no observable effect for verification purposes.
394	void srand(unsigned int seed) { (void)seed; }
395	
396	// Helper macro for addRandom's postcondition.
397	//
398	// NOTE on spec strength: avocado runs CBMC with a fixed, shallow `--depth`
399	// bound. The full collection loop in addRandom is long enough that its complete
400	// path exceeds that bound, so the postcondition is only ever *reached* on
401	// shorter paths (e.g. mutants that disable the scan loops and leave the board
402	// untouched). Crucially, `__CPROVER_old` history snapshots also consume depth,
403	// so a relational "some cell changed" postcondition becomes unreachable too.
404	// The postcondition below is therefore phrased purely over the post-state (no
405	// history), keeping it cheap enough to be reached on those shorter paths.
406	// After addRandom the board always has at least one non-empty cell: if it had
407	// an empty cell, exactly one gets filled with a 1- or 2-valued tile; if it was
408	// already full, every cell stays non-empty. A mutant that disables the scan
409	// loops leaves an all-empty input board untouched and violates this. The
410	// property is phrased as a single existential over the flat 16-byte board so
411	// it stays cheap in the shallow depth budget (see note above).
412	#define AR_SOME_NONEMPTY                                  \
413		__CPROVER_exists                                      \
414		{                                                    \
415			int _k;                                          \
416			(0 <= _k && _k < SIZE *SIZE) &&                  \
417				((uint8_t *)board)[_k] != 0                  \
418		}
419	
420	void addRandom(uint8_t board[SIZE][SIZE])
421	// clang-format off
422	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
423	__CPROVER_assigns(__CPROVER_object_whole(board))
424	__CPROVER_ensures(AR_SOME_NONEMPTY)
425	// clang-format on
426	{
427		static bool initialized = false;
428		uint8_t x, y;
429		uint8_t r, len = 0;
430		uint8_t n, list[SIZE * SIZE][2];
431	
432		if (!initialized)
433		{
434			srand(time(NULL));
435			initialized = true;
436		}
437	
438		for (x = 0; x < SIZE; x++)
439		{
440			for (y = 0; y < SIZE; y++)
441			{
442				if (board[x][y] == 0)
443				{
444					list[len][0] = x;
445					list[len][1] = y;
446					len++;
447				}
448			}
449		}
450	
451		if (len > 0)
452		{
453			r = rand() % len;
454			x = list[r][0];
455			y = list[r][1];
456			n = (rand() % 10) / 9 + 1;
457			board[x][y] = n;
458		}
459	}
460	
461	void initBoard(uint8_t board[SIZE][SIZE])
462	{
463		uint8_t x, y;
464		for (x = 0; x < SIZE; x++)
465		{
466			for (y = 0; y < SIZE; y++)
467			{
468				board[x][y] = 0;
469			}
470		}
471		addRandom(board);
472		addRandom(board);
473	}
474	
475	void setBufferedInput(bool enable)
476	{
477		static bool enabled = true;
478		static struct termios old;
479		struct termios new;
480	
481		if (enable && !enabled)
482		{
483			// restore the former settings
484			tcsetattr(STDIN_FILENO, TCSANOW, &old);
485			// set the new state
486			enabled = true;
487		}
488		else if (!enable && enabled)
489		{
490			// get the terminal settings for standard input
491			tcgetattr(STDIN_FILENO, &new);
492			// we want to keep the old setting to restore them at the end
493			old = new;
494			// disable canonical mode (buffered i/o) and local echo
495			new.c_lflag &= (~ICANON & ~ECHO);
496			// set the new settings immediately
497			tcsetattr(STDIN_FILENO, TCSANOW, &new);
498			// set the new state
499			enabled = false;
500		}
501	}
502	
503	bool testSucceed()
504	{
505		uint8_t array[SIZE];
506		// these are exponents with base 2 (1=2 2=4 3=8)
507		// data holds per line: 4x IN, 4x OUT, 1x POINTS
508		uint8_t data[] = {
509			0, 0, 0, 1, 1, 0, 0, 0, 0,
510			0, 0, 1, 1, 2, 0, 0, 0, 4,
511			0, 1, 0, 1, 2, 0, 0, 0, 4,
512			1, 0, 0, 1, 2, 0, 0, 0, 4,
513			1, 0, 1, 0, 2, 0, 0, 0, 4,
514			1, 1, 1, 0, 2, 1, 0, 0, 4,
515			1, 0, 1, 1, 2, 1, 0, 0, 4,
516			1, 1, 0, 1, 2, 1, 0, 0, 4,
517			1, 1, 1, 1, 2, 2, 0, 0, 8,
518			2, 2, 1, 1, 3, 2, 0, 0, 12,
519			1, 1, 2, 2, 2, 3, 0, 0, 12,
520			3, 0, 1, 1, 3, 2, 0, 0, 4,
521			2, 0, 1, 1, 2, 2, 0, 0, 4};
522		uint8_t *in, *out, *points;
523		uint8_t t, tests;
524		uint8_t i;
525		bool success = true;
526		uint32_t score;
527	
528		tests = (sizeof(data) / sizeof(data[0])) / (2 * SIZE + 1);
529		for (t = 0; t < tests; t++)
530		{
531			in = data + t * (2 * SIZE + 1);
532			out = in + SIZE;
533			points = in + 2 * SIZE;
534			for (i = 0; i < SIZE; i++)
535			{
536				array[i] = in[i];
537			}
538			score = 0;
539			slideArray(array, &score);
540			for (i = 0; i < SIZE; i++)
541			{
542				if (array[i] != out[i])
543				{
544					success = false;
545				}
546			}
547			if (score != *points)
548			{
549				success = false;
550			}
551			if (success == false)
552			{
553				for (i = 0; i < SIZE; i++)
554				{
555					printf("%u ", in[i]);
556				}
557				printf("=> ");
558				for (i = 0; i < SIZE; i++)
559				{
560					printf("%u ", array[i]);
561				}
562				printf("(%u points) expected ", score);
563				for (i = 0; i < SIZE; i++)
564				{
565					printf("%u ", in[i]);
566				}
567				printf("=> ");
568				for (i = 0; i < SIZE; i++)
569				{
570					printf("%u ", out[i]);
571				}
572				printf("(%u points)\n", *points);
573				break;
574			}
575		}
576		if (success)
577		{
578			printf("All %u tests executed successfully\n", tests);
579		}
580		return success;
581	}
582	
583	void signal_callback_handler(int signum)
584	{
585		printf("         TERMINATED         \n");
586		setBufferedInput(true);
587		// make cursor visible, reset all modes
588		printf("\033[?25h\033[m");
589		exit(signum);
590	}
591	
592	int main(int argc, char *argv[])
593	{
594		uint8_t board[SIZE][SIZE];
595		uint8_t scheme = 0;
596		uint32_t score = 0;
597		int c;
598		bool success;
599	
600		// handle the command line options
601		if (argc > 1)
602		{
603			if (strcmp(argv[1], "-h") == 0 || strcmp(argv[1], "--help") == 0)
604			{
605				printf("Usage: 2048 [OPTION] | [MODE]\n");
606				printf("Play the game 2048 in the console\n\n");
607				printf("Options:\n");
608				printf("  -h,  --help       Show this help message.\n");
609				printf("  -v,  --version    Show version number.\n\n");
610				printf("Modes:\n");
611				printf("  bluered      Use a blue-to-red color scheme (requires 256-color terminal support).\n");
612				printf("  blackwhite   The black-to-white color scheme (requires 256-color terminal support).\n");
613				return EXIT_SUCCESS;
614			}
615			else if (strcmp(argv[1], "-v") == 0 || strcmp(argv[1], "--version") == 0)
616			{
617				printf("2048.c version %s\n", VERSION);
618				return EXIT_SUCCESS;
619			}
620			else if (strcmp(argv[1], "blackwhite") == 0)
621			{
622				scheme = 1;
623			}
624			else if (strcmp(argv[1], "bluered") == 0)
625			{
626				scheme = 2;
627			}
628			else if (strcmp(argv[1], "whiteblack") == 0)
629			{
630				scheme = 3;
631			}
632			else if (strcmp(argv[1], "test") == 0)
633			{
634				return testSucceed() ? EXIT_SUCCESS : EXIT_FAILURE;
635			}
636			else
637			{
638				printf("Invalid option: %s\n\nTry '%s --help' for more options.\n", argv[1], argv[0]);
639				return EXIT_FAILURE;
640			}
641		}
642	
643		// make cursor invisible, erase entire screen
644		printf("\033[?25l\033[2J");
645	
646		// register signal handler for when ctrl-c is pressed
647		signal(SIGINT, signal_callback_handler);
648	
649		initBoard(board);
650		setBufferedInput(false);
651		drawBoard(board, scheme, score);
652		while (true)
653		{
654			c = getchar();
655			if (c == EOF)
656			{
657				puts("\nError! Cannot read keyboard input!");
658				break;
659			}
660			switch (c)
661			{
662			case 52:  // '4' key
663			case 97:  // 'a' key
664			case 104: // 'h' key
665			case 68:  // left arrow
666				success = moveLeft(board, &score);
667				break;
668			case 54:  // '6' key
669			case 100: // 'd' key
670			case 108: // 'l' key
671			case 67:  // right arrow
672				success = moveRight(board, &score);
673				break;
674			case 56:  // '8' key
675			case 119: // 'w' key
676			case 107: // 'k' key
677			case 65:  // up arrow
678				success = moveUp(board, &score);
679				break;
680			case 50:  // '2' key
681			case 115: // 's' key
682			case 106: // 'j' key
683			case 66:  // down arrow
684				success = moveDown(board, &score);
685				break;
686			default:
687				success = false;
688			}
689			if (success)
690			{
691				drawBoard(board, scheme, score);
692				usleep(150 * 1000); // 150 ms
693				addRandom(board);
694				drawBoard(board, scheme, score);
695				if (gameEnded(board))
696				{
697					printf("         GAME OVER          \n");
698					break;
699				}
700			}
701			if (c == 'q')
702			{
703				printf("        QUIT? (y/n)         \n");
704				c = getchar();
705				if (c == 'y')
706				{
707					break;
708				}
709				drawBoard(board, scheme, score);
710			}
711			if (c == 'r')
712			{
713				printf("       RESTART? (y/n)       \n");
714				c = getchar();
715				if (c == 'y')
716				{
717					initBoard(board);
718					score = 0;
719				}
720				drawBoard(board, scheme, score);
721			}
722		}
723		setBufferedInput(true);
724	
725		// make cursor visible, reset all modes
726		printf("\033[?25h\033[m");
727	
728		return EXIT_SUCCESS;
729	}
